user_prompt_template:
Analyze the following inputs and produce a RESOLVED_JSON decision document.

## BRIEF
{brief_text}

## ASSETS PROVIDED
- Talent image: PROVIDED (identity locked)
- Garments: {garment_count} items (all must be used)
- Brand logo: {logo_status}
- Pose reference: {pose_ref_status}
- Photo style references: {style_ref_status}
- Location references: {location_ref_status}

## SELECTED PACKS
- Intent: {intent}
- Camera: {camera_pack}
- Shot: {shot_pack}
- Lighting: {lighting_pack}
- Environment: {environment_pack}
- Style: {style_pack}
- Branding: {branding_pack}
- Lens: {lens_pack}
- Film Texture: {film_texture_pack}
- Color Science: {color_science_pack}
- Time Weather: {time_weather_pack}
- Pose Discipline: {pose_discipline_pack}
- Studio Override: {studio_override}

## FORMAT
{format}

Produce a JSON with this EXACT structure (packs_applied and rendering are REQUIRED):
{
  "subject": { "description": "...", "identity_lock": true, "gender": "...", "traits": [...] },
  "wardrobe": { "items": [...], "fit_priority": "high/very_high", "styling_notes": "..." },
  "pose": { "type": "...", "description": "...", "reference_used": true/false },
  "photography": { "camera": "...", "shot": "...", "framing": "..." },
  "lighting": { "type": "...", "mood": "...", "description": "..." },
  "environment": { "type": "...", "description": "...", "studio_override_applied": true/false },
  "style": { "aesthetic": "...", "color_grading": "...", "mood": "..." },
  "branding": { "logo_used": true/false, "placement": "...", "treatment": "..." },
  "packs_applied": {
    "selected": { "lens_pack": "...", "film_texture_pack": "...", "color_science_pack": "...", "time_weather_pack": "...", "pose_discipline_pack": "..." },
    "effective": { "lens_pack": "...", "film_texture_pack": "...", "color_science_pack": "...", "time_weather_pack": "...", "pose_discipline_pack": "..." },
    "fragments": { "lens": "prompt text", "film_texture": "prompt text", "color_science": "prompt text", "time_weather": "prompt text", "pose_discipline": "prompt text" }
  },
  "rendering": { "lens": "...", "film_texture": "...", "color_science": "...", "time_weather": "...", "pose_discipline": "..." },
  "intent_applied": "...",
  "format": "..."
}
